{
  "phase": "question",
  "questions": [
    {
      "id": "q1",
      "question": "Should WebSocket endpoint tests be included in scope, or should we focus only on HTTP REST endpoints? The WebSocket handlers (_handle_risk_websocket, _handle_market_websocket) have zero test coverage but may require a different test harness.",
      "category": "requirements",
      "why_it_matters": "WebSocket testing requires a different client library and test patterns than the existing unittest-based HTTP tests. Including them significantly increases complexity and may warrant a separate task."
    },
    {
      "id": "q2",
      "question": "Should new tests be added to the existing test_bayes_market_api.py (9,900 lines) or should we create a new test file for the new coverage?",
      "category": "design",
      "why_it_matters": "The existing file is already very large. Adding more tests there follows existing patterns but hurts maintainability. A new file needs to replicate setup/helper patterns."
    },
    {
      "id": "q3",
      "question": "Are there specific error codes or failure modes that have been observed in production that should be prioritized for test coverage?",
      "category": "requirements",
      "why_it_matters": "The task says 'focus on error paths and edge cases' - knowing which errors have actually occurred in production would help prioritize the most impactful tests to write."
    }
  ],
  "assumptions": [
    {
      "id": "a1",
      "assumption": "WebSocket endpoints are out of scope - we should focus on HTTP REST endpoint gaps like 500 error handling, market state transition validation, and large payload edge cases.",
      "confidence": 0.7,
      "if_wrong": "Would need to add websocket-client dependency and write a different test harness for WebSocket upgrade/messaging tests."
    },
    {
      "id": "a2",
      "assumption": "New tests should be added to the existing test_bayes_market_api.py file to follow established patterns and use existing helper functions.",
      "confidence": 0.8,
      "if_wrong": "Would need to extract shared helpers into a conftest.py or test utilities module and create a separate test file."
    },
    {
      "id": "a3",
      "assumption": "The three best candidates for new test coverage are: (1) 500 error handling when handlers raise unexpected exceptions, (2) market detail endpoint edge cases (non-existent market, resolved market state), (3) event trade endpoint edge cases (position limit boundaries, concurrent position updates).",
      "confidence": 0.75,
      "if_wrong": "May need to adjust which endpoints to target based on actual gaps vs what the task owner considers important."
    },
    {
      "id": "a4",
      "assumption": "Tests should use the same unittest.TestCase pattern with server.route_request() calls, not spinning up an HTTP server.",
      "confidence": 0.9,
      "if_wrong": "Would need to use the BayesMarketApiConcurrencyTests pattern with ThreadingHTTPServer instead."
    },
    {
      "id": "a5",
      "assumption": "The target endpoints for new error/edge-case tests are: GET /v1/markets/{id}/analytics (edge cases like empty markets, invalid time ranges), POST /v1/markets/{id}/resolve (concurrent resolution, partial settlement), and GET /v1/accounts/{id}/pnl (account with no trades, account with only resolved markets).",
      "confidence": 0.65,
      "if_wrong": "Different endpoints may have more critical untested paths that would be more valuable to cover."
    }
  ],
  "decomposition_assessment": {
    "complexity_score": 2,
    "complexity_reason": "Adding tests to an existing well-structured test suite with clear patterns. Changes are limited to 1 file, test helpers already exist, and the patterns are well-established. Need to write ~3-5 test functions per endpoint for 3 endpoints.",
    "uncertainty_score": 2,
    "uncertainty_reason": "The codebase is well-explored, test patterns are clear, and the gaps are identified. Main uncertainty is which specific edge cases will be most valuable, but the server code is readable and error paths are identifiable from the source.",
    "independent_subproblems": [
      "Write error path tests for endpoint group 1 (e.g., analytics edge cases)",
      "Write error path tests for endpoint group 2 (e.g., resolution edge cases)",
      "Write error path tests for endpoint group 3 (e.g., account PnL edge cases)"
    ],
    "decision": "PROCEED_ALONE",
    "decision_reason": "Complexity is low (score 2) and uncertainty is low (score 2). While there are 3 independent sub-problems, they all follow the same patterns, share the same file, and benefit from consistent style. Parallelizing would add coordination overhead without meaningful speed gain for ~15-20 test functions."
  },
  "spawn_children": false,
  "children": []
}

{
  "phase": "plan",
  "decisions": [
    {
      "id": "d1",
      "decision": "Exclude WebSocket endpoints from scope — they require a fundamentally different test harness (raw TCP sockets, RFC 6455 framing, async coordination) and warrant a separate task",
      "based_on": ["q1"],
      "alternatives_rejected": ["Include WebSocket tests using websocket-client dependency", "Build a raw socket test client for RFC 6455"],
      "reversibility": "easy"
    },
    {
      "id": "d2",
      "decision": "Add new tests to the existing test_bayes_market_api.py file, using existing test classes where appropriate and creating new focused classes where needed",
      "based_on": ["q2"],
      "alternatives_rejected": ["Create a new test file (would require duplicating ~400 lines of helpers or extracting them first)", "Extract helpers into conftest.py (scope creep)"],
      "reversibility": "easy"
    },
    {
      "id": "d3",
      "decision": "Focus on four confirmed coverage gaps: (1) inference adapter 500 error handling (zero tests for status 500), (2) probability-edit 500→fallback path, (3) account PnL double-404 edge case, (4) analytics malformed-timestamp silent skip. The original assumptions about analytics and resolve being top targets were corrected — both already have 7+ and 10+ tests respectively",
      "based_on": ["q3"],
      "alternatives_rejected": ["Target analytics endpoint (already has 7 tests)", "Target resolve endpoint (already has 10+ tests)", "Target event-trade on non-active market (already tested extensively)"],
      "reversibility": "easy"
    },
    {
      "id": "d4",
      "decision": "Use the route_request() direct-call pattern for most tests, with unittest.mock.patch for triggering internal error paths (inference adapter errors, fallback paths). Only use HTTP server for tests that verify HTTP-layer behavior",
      "based_on": ["q2"],
      "alternatives_rejected": ["Use HTTP server for all tests (unnecessary overhead for error-path testing)", "Avoid mocking entirely (impossible to trigger 500 paths without it)"],
      "reversibility": "easy"
    }
  ],
  "steps": [
    {
      "step": 1,
      "task": "Add 500 error handling tests for inference adapter failures. Patch the 3 adapter call sites (compile_market at server.py:1275, query_marginals at server.py:1304, query_atomic_event at server.py:1323) to raise InferenceCompileError/InferenceQueryError. Verify route_request raises ApiError(500, 'internal_error'). Add tests to BayesMarketApiUnitTests or a new BayesMarketInternalErrorTests class in test_bayes_market_api.py.",
      "depends_on": [],
      "estimated_lines": 80,
      "risk": "medium"
    },
    {
      "step": 2,
      "task": "Add probability-edit 500→fallback path test. Patch resolve_probability_edit_base_marginals (server.py:3875) to raise ApiError(500, 'internal_error'). Verify the handler catches it, calls fallback_probability_edit_base_marginals, and the edit still succeeds with status 201. Add to BayesMarketApiUnitTests.",
      "depends_on": [],
      "estimated_lines": 50,
      "risk": "medium"
    },
    {
      "step": 3,
      "task": "Add account PnL double-404 edge case test. Directly insert an order with an unrecognized type into server.ORDERS so the first check (line 2326-2336) finds orders but compute_orders_pnl returns empty for all markets, triggering the second 404 at line 2355-2361. Add to BayesMarketPnlTests.",
      "depends_on": [],
      "estimated_lines": 40,
      "risk": "low"
    },
    {
      "step": 4,
      "task": "Add analytics malformed-timestamp edge case test. Create a market with events that have invalid ISO timestamp strings in emittedAt. Verify the analytics endpoint silently skips those events and returns valid price-history buckets for the well-formed events only. Add to BayesMarketAnalyticsTests.",
      "depends_on": [],
      "estimated_lines": 40,
      "risk": "low"
    },
    {
      "step": 5,
      "task": "Run full test suite (python -m pytest tests/test_bayes_market_api.py) to verify all new and existing tests pass. Fix any failures.",
      "depends_on": [1, 2, 3, 4],
      "estimated_lines": 0,
      "risk": "low"
    }
  ],
  "decomposition_assessment": {
    "total_steps": 5,
    "estimated_total_lines": 210,
    "high_risk_steps": 0,
    "parallelizable_groups": [["step1", "step2", "step3", "step4"], ["step5"]],
    "decision": "PROCEED_ALONE",
    "decision_reason": "Total estimated lines (210) is well under the 500 threshold. Zero high-risk steps (medium-risk steps 1-2 involve mocking but are straightforward). While steps 1-4 are parallelizable, they all modify the same file (test_bayes_market_api.py) so parallel execution would cause merge conflicts. The test patterns are well-established and all steps follow the same route_request() + assertRaises/assertEqual pattern."
  },
  "spawn_children": false,
  "children": []
}

